const express = require('express');
const { MongoClient, ObjectId } = require('mongodb');

const app = express();
app.use(express.json());

const MONGO_URI = process.env.MONGO_URI || 'mongodb://localhost:27017';
const DB_NAME = process.env.DB_NAME || 'queryservice';

let db;

async function connectToMongo() {
  const client = new MongoClient(MONGO_URI);
  await client.connect();
  db = client.db(DB_NAME);
  console.log('Connected to MongoDB');
  return client;
}

// Sanitize user input to prevent NoSQL injection
function sanitizeFilter(obj) {
  if (obj === null || obj === undefined) return obj;
  if (typeof obj !== 'object') return obj;

  if (Array.isArray(obj)) {
    return obj.map(item => sanitizeFilter(item));
  }

  // Allowed MongoDB query operators (whitelist approach)
  const allowedOperators = new Set([
    '$gt', '$gte', '$lt', '$lte', '$eq', '$ne',
    '$in', '$nin', '$regex', '$options',
    '$exists', '$type',
    '$and', '$or', '$nor', '$not',
    '$elemMatch', '$size', '$all',
    '$mod', '$text', '$search', '$language', '$caseSensitive', '$diacriticSensitive'
  ]);

  // Dangerous operators that should never be allowed from user input
  const blockedOperators = new Set([
    '$where', '$function', '$accumulator',
    '$expr', '$jsonSchema',
    '$lookup', '$merge', '$out',
    '$group', '$project', '$unwind',
    '$replaceRoot', '$replaceWith',
    '$set', '$unset', '$rename',
    '$currentOp', '$listSessions',
    '$comment'
  ]);

  const sanitized = {};

  for (const [key, value] of Object.entries(obj)) {
    // Block dangerous operators
    if (blockedOperators.has(key)) {
      console.warn(`Blocked dangerous operator: ${key}`);
      continue;
    }

    // If key starts with $ but is not in allowed list, skip it
    if (key.startsWith('$') && !allowedOperators.has(key)) {
      console.warn(`Blocked unknown operator: ${key}`);
      continue;
    }

    // Recursively sanitize nested objects
    if (typeof value === 'object' && value !== null) {
      sanitized[key] = sanitizeFilter(value);
    } else {
      sanitized[key] = value;
    }
  }

  return sanitized;
}

// Validate and parse projection
function sanitizeProjection(proj) {
  if (!proj || typeof proj !== 'object' || Array.isArray(proj)) return {};

  const sanitized = {};
  for (const [key, value] of Object.entries(proj)) {
    if (typeof key === 'string' && !key.startsWith('$')) {
      if (value === 1 || value === 0 || value === true || value === false) {
        sanitized[key] = value;
      }
    }
  }
  return sanitized;
}

// Validate sort options
function sanitizeSort(sort) {
  if (!sort || typeof sort !== 'object' || Array.isArray(sort)) return {};

  const sanitized = {};
  for (const [key, value] of Object.entries(sort)) {
    if (typeof key === 'string' && !key.startsWith('$')) {
      if (value === 1 || value === -1) {
        sanitized[key] = value;
      }
    }
  }
  return sanitized;
}

// POST /api/query/:collection - Query a collection with filters
app.post('/api/query/:collection', async (req, res) => {
  try {
    const collectionName = req.params.collection;

    // Validate collection name (alphanumeric and underscores only)
    if (!/^[a-zA-Z0-9_]+$/.test(collectionName)) {
      return res.status(400).json({ error: 'Invalid collection name' });
    }

    const {
      filter = {},
      projection = {},
      sort = {},
      limit = 100,
      skip = 0
    } = req.body;

    // Enforce maximum limit to prevent abuse
    const maxLimit = 1000;
    const safeLimit = Math.min(Math.max(parseInt(limit) || 100, 1), maxLimit);
    const safeSkip = Math.max(parseInt(skip) || 0, 0);

    const sanitizedFilter = sanitizeFilter(filter);
    const sanitizedProjection = sanitizeProjection(projection);
    const sanitizedSort = sanitizeSort(sort);

    console.log('Collection:', collectionName);
    console.log('Sanitized Filter:', JSON.stringify(sanitizedFilter));

    const collection = db.collection(collectionName);

    const results = await collection
      .find(sanitizedFilter)
      .project(sanitizedProjection)
      .sort(sanitizedSort)
      .skip(safeSkip)
      .limit(safeLimit)
      .toArray();

    const totalCount = await collection.countDocuments(sanitizedFilter);

    res.json({
      success: true,
      data: results,
      metadata: {
        total: totalCount,
        returned: results.length,
        skip: safeSkip,
        limit: safeLimit
      }
    });
  } catch (error) {
    console.error('Query error:', error.message);
    res.status(500).json({ error: 'Query execution failed', message: error.message });
  }
});

