// POST /api/aggregate/:collection - Run aggregation pipeline
app.post('/api/aggregate/:collection', async (req, res) => {
  try {
    const collectionName = req.params.collection;

    if (!/^[a-zA-Z0-9_]+$/.test(collectionName)) {
      return res.status(400).json({ error: 'Invalid collection name' });
    }

    const { pipeline = [] } = req.body;

    if (!Array.isArray(pipeline)) {
      return res.status(400).json({ error: 'Pipeline must be an array' });
    }

    // Block dangerous aggregation stages
    const blockedStages = new Set([
      '$out', '$merge', '$lookup', '$graphLookup',
      '$currentOp', '$listSessions', '$listLocalSessions',
      '$collStats', '$indexStats', '$planCacheStats',
      '$function', '$accumulator'
    ]);

    for (const stage of pipeline) {
      const stageKeys = Object.keys(stage);
      for (const key of stageKeys) {
        if (blockedStages.has(key)) {
          return res.status(400).json({ error: `Aggregation stage ${key} is not allowed` });
        }
      }
    }

    // Enforce a result limit if no $limit stage exists
    const hasLimit = pipeline.some(stage => '$limit' in stage);
    if (!hasLimit) {
      pipeline.push({ $limit: 1000 });
    }

    const collection = db.collection(collectionName);
    const results = await collection.aggregate(pipeline).toArray();

    res.json({
      success: true,
      data: results,
      count: results.length
    });
  } catch (error) {
    console.error('Aggregation error:', error.message);
    res.status(500).json({ error: 'Aggregation failed', message: error.message });
  }
});

