// GET /api/findone/:collection/:id - Find document by ID
app.get('/api/findone/:collection/:id', async (req, res) => {
  try {
    const collectionName = req.params.collection;
    const id = req.params.id;

    if (!/^[a-zA-Z0-9_]+$/.test(collectionName)) {
      return res.status(400).json({ error: 'Invalid collection name' });
    }

    let filter;
    try {
      filter = { _id: new ObjectId(id) };
    } catch {
      filter = { _id: id };
    }

    const collection = db.collection(collectionName);
    const result = await collection.findOne(filter);

    if (!result) {
      return res.status(404).json({ success: false, error: 'Document not found' });
    }

    res.json({ success: true, data: result });
  } catch (error) {
    console.error('FindOne error:', error.message);
    res.status(500).json({ error: 'FindOne operation failed', message: error.message });
  }
});

